+//! FCP Anthropic Connector - Main entrypoint
+//!
+//! An Anthropic Claude API connector implementing the Flywheel Connector Protocol.
+//! Provides access to Claude models with cost tracking and streaming support.
+
+#![forbid(unsafe_code)]
+
+use std::io::{BufRead, Write};
+
+use anyhow::Result;
+use tracing_subscriber::{layer::SubscriberExt, util::SubscriberInitExt, EnvFilter};
+
+mod client;
+mod connector;
+mod error;
+mod types;
+
+use connector::AnthropicConnector;
+
+fn main() -> Result<()> {
+    // Initialize tracing
+    tracing_subscriber::registry()
+        .with(EnvFilter::try_from_default_env().unwrap_or_else(|_| EnvFilter::new("info")))
+        .with(tracing_subscriber::fmt::layer().with_writer(std::io::stderr))
+        .init();
+
+    tracing::info!("FCP Anthropic Connector starting");
+
+    // Run the FCP protocol loop on stdin/stdout
+    run_fcp_loop()?;
+
+    Ok(())
+}
+
+/// Run the FCP JSON-RPC style protocol loop.
+fn run_fcp_loop() -> Result<()> {
+    let stdin = std::io::stdin();
+    let mut stdout = std::io::stdout();
+    let mut connector = AnthropicConnector::new();
+
+    let runtime = tokio::runtime::Builder::new_multi_thread()
+        .enable_all()
+        .build()?;
+
+    for line in stdin.lock().lines() {
+        let line = line?;
+        if line.is_empty() {
+            continue;
+        }
+
+        let response = runtime.block_on(async { handle_message(&mut connector, &line).await });
+
+        let response_json = serde_json::to_string(&response)?;
+        writeln!(stdout, "{response_json}")?;
+        stdout.flush()?;
+    }
+
+    Ok(())
+}
+
+/// Handle a single FCP message.
+async fn handle_message(connector: &mut AnthropicConnector, message: &str) -> serde_json::Value {
+    let request: serde_json::Value = match serde_json::from_str(message) {
+        Ok(v) => v,
+        Err(e) => {
+            return serde_json::json!({
+                "error": {
+                    "code": "FCP-1001",
+                    "message": format!("Invalid JSON: {e}")
+                }
+            });
+        }
+    };
+
+    let method = request
+        .get("method")
+        .and_then(|v| v.as_str())
+        .unwrap_or("");
+    let id = request.get("id").cloned();
+    let params = request
+        .get("params")
+        .cloned()
+        .unwrap_or(serde_json::json!({}));
+
+    let result = match method {
+        "configure" => connector.handle_configure(params).await,
+        "handshake" => connector.handle_handshake(params).await,
+        "health" => connector.handle_health().await,
+        "introspect" => connector.handle_introspect().await,
+        "invoke" => connector.handle_invoke(params).await,
+        "shutdown" => connector.handle_shutdown(params).await,
+        _ => Err(fcp_core::FcpError::InvalidRequest {
+            code: 1002,
+            message: format!("Unknown method: {method}"),
+        }),
+    };
+
+    match result {
+        Ok(value) => {
+            let mut response = serde_json::json!({
+                "jsonrpc": "2.0",
+                "result": value
+            });
+            if let Some(id) = id {
+                response["id"] = id;
+            }
+            response
+        }
+        Err(e) => {
+            let err_response = e.to_response();
+            let mut response = serde_json::json!({
+                "jsonrpc": "2.0",
+                "error": err_response
+            });
+            if let Some(id) = id {
+                response["id"] = id;
+            }
+            response
+        }
+    }
+}
